// Derived helpers

/** All letters that have at least one entry */
export const availableLetters: string[] = [...new Set(curatedIndex.map(e => e.letter))].sort();

/** Get all entries for a given letter */
export function getEntriesByLetter(letter: string): IndexEntry[] {
  return curatedIndex.filter(e => e.letter === letter.toUpperCase());
}

/** Get only gene entries for a given letter */
export function getGenesByLetter(letter: string): IndexEntry[] {
  return curatedIndex.filter(e => e.letter === letter.toUpperCase() && e.type === "gene");
}

/** Get only condition entries for a given letter */
export function getConditionsByLetter(letter: string): IndexEntry[] {
  return curatedIndex.filter(e => e.letter === letter.toUpperCase() && e.type === "condition");
}

/** Search by name (case-insensitive substring match) */
export function searchIndex(query: string): IndexEntry[] {
  const q = query.toLowerCase();
  return curatedIndex.filter(e => e.name.toLowerCase().includes(q));
}